<div class="dashboard-grid">
 <section class="panel"><h2>Добавить рубрику</h2><form method="post" action="<?=e(app_url('/studio/categories/save'))?>"><?=csrf_field()?><div class="field"><label>Название</label><input name="name" maxlength="150" required></div><div class="field"><label>Адрес</label><input name="slug" maxlength="150" placeholder="zapisi-o-proekte"></div><div class="field"><label>Описание</label><textarea name="description" rows="4" maxlength="2000"></textarea></div><div class="field"><label>Порядок</label><input type="number" name="sort_order" value="0"></div><button class="button primary">Создать рубрику</button></form></section>
